// mermaid-interop.src.js — source for esbuild bundle (mermaid-interop.js)
// Uses Mermaid.js ^11.14.0
// DO NOT edit mermaid-interop.js directly — it is regenerated by `npm run build`
import mermaid from 'mermaid';

let _initialized = false;

export async function initMermaid(isDark) {
    const style = getComputedStyle(document.documentElement);
    const v = (name) => style.getPropertyValue(name).trim();

    mermaid.initialize({
        startOnLoad: false,
        theme: 'base',
        themeVariables: {
            git0: v('--gitvis-mermaid-branch-0'),
            git1: v('--gitvis-mermaid-branch-1'),
            git2: v('--gitvis-mermaid-branch-2'),
            git3: v('--gitvis-mermaid-branch-3'),
            git4: v('--gitvis-mermaid-branch-4'),
            git5: v('--gitvis-mermaid-branch-5'),
            gitBranchLabel0: v('--gitvis-mermaid-node-text'),
            gitBranchLabel1: v('--gitvis-mermaid-node-text'),
            gitBranchLabel2: v('--gitvis-mermaid-node-text'),
            gitBranchLabel3: v('--gitvis-mermaid-node-text'),
            gitBranchLabel4: v('--gitvis-mermaid-node-text'),
            gitBranchLabel5: v('--gitvis-mermaid-node-text'),
            gitInv0: v('--gitvis-mermaid-bg'),
            background: v('--gitvis-mermaid-bg'),
            primaryTextColor: v('--gitvis-mermaid-node-text'),
            lineColor: v('--gitvis-mermaid-edge'),
        }
    });
    _initialized = true;
}

export async function renderGraph(containerId, syntax) {
    const container = document.getElementById(containerId);
    if (!container || !syntax) return;
    if (!_initialized) return;
    const id = 'mermaid-render-' + Date.now();
    try {
        const { svg } = await mermaid.render(id, syntax);
        container.innerHTML = svg;
    } catch (e) {
        container.innerHTML = `<p style="color:var(--mud-palette-warning-text)">Graph render error: ${e.message}</p>`;
    }
}

export function scrollToHead(containerId) {
    const container = document.getElementById(containerId);
    if (!container) return;
    const head = container.querySelector('.commit-highlight');
    if (head) {
        head.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'end' });
    } else {
        container.scrollLeft = container.scrollWidth;
    }
}
